    postconditions=[{'when': 'always', 'guarantees': ['result == "Not Possible" or result == len(str1) // 2']}, {'when': 'len(str1) == len(str2)', 'guarantees': ['result >= 0']}],
)

@certus(
    preconditions=['isinstance(tuple_list, list)'],
    postconditions=[{'when': 'always', 'guarantees': ['result >= 0']}],
)

@certus(
    preconditions=['isinstance(arr1, list)', 'isinstance(arr2, list)', 'len(arr1) == m', 'len(arr2) == n', 'm >= 0', 'n >= 0', 'k > 0', 'k <= m + n'],
    postconditions=[{'when': 'always', 'guarantees': ['result in arr1 or result in arr2', 'result == sorted(arr1 + arr2)[k-1]', 'result == min(max(arr1[:k]), max(arr2[:k]))']}],
)

@certus(
    preconditions=['isinstance(number, int)', 'number >= 0'],
    postconditions=[{'when': 'always', 'guarantees': ['result in (True, False)']}],
)

@certus(
    preconditions=['isinstance(number, int)', 'number > 0'],
    postconditions=[{'when': 'always', 'guarantees': ['isinstance(result, tuple)', 'len(result) == 2', 'result[0] == sum(range(1, number + 1))', 'result[1] == result[0] / number']}],
)

@certus(
    preconditions=['isinstance(n, int)'],
    postconditions=[{'when': 'always', 'guarantees': ['result in (True, False)', 'result == (n % 2 == 0)']}],
)
